// ============================================================
// Discovery Cleanup Daily Sweep
// ------------------------------------------------------------
// Identical sweep logic to the manual 'Discovery Cleanup Replay'
// workflow, but fires automatically every day at 14:00 UTC.
//
// Recovers grants that got stuck in stage='discovery' because of
// an n8n container restart, screener timeout, or any transient
// failure between the 'add to pipeline' step and the screener.
//
// For each stuck grant:
//   1. If deadline already passed -> PATCH stage='closed' (and log
//      'grant_auto_closed_expired' in activity_log).
//   2. Otherwise -> POST it to the Screening Throttle Queue, which
//      paces calls into the Grant Eligibility Screener so we don't
//      flood the worker pool.
//
// DRY_RUN is FALSE here (this is the production scheduled sweep);
// flip to true if you ever need to inspect the counts without
// mutating.
// ============================================================

const DRY_RUN        = false;
const BATCH_SIZE     = 100;
const BATCH_DELAY_MS = 2000;
const PAGE_SIZE      = 1000;

const SUPABASE_URL = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
const THROTTLE_URL = 'https://n8n.thebrownmine.com/webhook/screen-queue';

const helpers = this.helpers;
const supaHeaders = {
  'apikey':        SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type':  'application/json',
};

function parseDeadline(v) {
  if (v === null || v === undefined) return null;
  const s = String(v).trim();
  if (!s) return null;
  const d = new Date(s);
  if (isNaN(d.getTime())) return null;
  return d;
}

function isExpired(deadline) {
  const d = parseDeadline(deadline);
  if (!d) return false;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return d.getTime() < today.getTime();
}

async function fetchAllDiscovery() {
  const all = [];
  let offset = 0;
  const selectCols = 'id,org_id,title,funder_name,description,amount,deadline,source,source_url,source_id,created_at';
  while (true) {
    const rows = await helpers.httpRequest({
      method:  'GET',
      url:     SUPABASE_URL + '/grants?stage=eq.discovery&select=' + selectCols + '&order=created_at.asc',
      headers: Object.assign({}, supaHeaders, {
        'Range-Unit': 'items',
        'Range':      offset + '-' + (offset + PAGE_SIZE - 1),
      }),
      json: true,
    });
    if (!Array.isArray(rows) || rows.length === 0) break;
    all.push.apply(all, rows);
    if (rows.length < PAGE_SIZE) break;
    offset += PAGE_SIZE;
  }
  return all;
}

async function closeExpired(grant) {
  if (DRY_RUN) return { ok: true };
  try {
    await helpers.httpRequest({
      method:  'PATCH',
      url:     SUPABASE_URL + '/grants?id=eq.' + encodeURIComponent(grant.id),
      headers: supaHeaders,
      body:    JSON.stringify({ stage: 'closed' }),
    });
    await helpers.httpRequest({
      method:  'POST',
      url:     SUPABASE_URL + '/activity_log',
      headers: supaHeaders,
      body:    JSON.stringify({
        org_id:   grant.org_id,
        grant_id: grant.id,
        action:   'grant_auto_closed_expired',
        details: {
          grant_name: grant.title,
          funder:     grant.funder_name,
          deadline:   grant.deadline,
          workflow:   'discovery_cleanup_daily_sweep',
          reason:     'Deadline passed while stuck in discovery stage',
        },
      }),
    });
    return { ok: true };
  } catch (e) {
    return { ok: false, message: String(e.message || e).slice(0, 400) };
  }
}

function toScreenPayload(g) {
  return {
    url:     g.source_url || '',
    grantid: g.id,
    orgId:   g.org_id || '',
    grantData: {
      title:       g.title || '',
      agency:      g.funder_name || '',
      awardRange:  g.amount ? String(g.amount) : 'Not specified',
      deadline:    g.deadline || '',
      description: g.description || '',
      source:      g.source || '',
      org_id:      g.org_id || '',
    },
  };
}

async function sendBatchToThrottle(batch) {
  if (DRY_RUN) return { ok: true, count: batch.length };
  try {
    await helpers.httpRequest({
      method:  'POST',
      url:     THROTTLE_URL,
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ grants: batch.map(toScreenPayload) }),
      timeout: 30000,
    });
    return { ok: true, count: batch.length };
  } catch (e) {
    return { ok: false, count: batch.length, message: String(e.message || e).slice(0, 400) };
  }
}

const grants = await fetchAllDiscovery();

const expired = [];
const replayable = [];
for (let i = 0; i < grants.length; i++) {
  const g = grants[i];
  if (isExpired(g.deadline)) expired.push(g);
  else replayable.push(g);
}

let closedOk = 0;
let closedFailed = 0;
const closeErrors = [];
for (let i = 0; i < expired.length; i++) {
  const r = await closeExpired(expired[i]);
  if (r.ok) closedOk++;
  else { closedFailed++; closeErrors.push({ id: expired[i].id, message: r.message }); }
}

let replayedOk = 0;
let replayedFailed = 0;
const replayErrors = [];
const batches = [];
for (let i = 0; i < replayable.length; i += BATCH_SIZE) {
  batches.push(replayable.slice(i, i + BATCH_SIZE));
}
for (let i = 0; i < batches.length; i++) {
  const r = await sendBatchToThrottle(batches[i]);
  if (r.ok) replayedOk += r.count;
  else { replayedFailed += r.count; replayErrors.push({ batch_index: i, message: r.message }); }
  if (i < batches.length - 1) {
    await new Promise(function (res) { setTimeout(res, BATCH_DELAY_MS); });
  }
}

return [{
  json: {
    ran_at:                       new Date().toISOString(),
    dry_run:                      DRY_RUN,
    total_discovery:              grants.length,
    expired_closed:               closedOk,
    expired_close_failed:         closedFailed,
    replayable_sent_to_throttle:  replayedOk,
    replayable_failed:            replayedFailed,
    batches_sent:                 batches.length,
    batch_size:                   BATCH_SIZE,
    errors: {
      closing:   closeErrors.slice(0, 20),
      replaying: replayErrors.slice(0, 20),
    },
  },
}];
